USE rvs_fishworld;

-- explanation: this stages the FoxPro product quantity and cost values before updating the live products table
DROP TEMPORARY TABLE IF EXISTS tmp_product_costs;
CREATE TEMPORARY TABLE tmp_product_costs (
    product_code VARCHAR(30) PRIMARY KEY,
    unit_of_measure VARCHAR(20),
    total_quantity DECIMAL(12,2) NOT NULL DEFAULT 0,
    previous_cost DECIMAL(12,4) NOT NULL DEFAULT 0,
    average_cost DECIMAL(12,4) NOT NULL DEFAULT 0
);








-- explanation: this updates only the products that already exist in MySQL using the real FoxPro cost and quantity values
UPDATE products p
JOIN tmp_product_costs t ON t.product_code = p.product_code
SET p.unit_of_measure = t.unit_of_measure,
    p.total_quantity = t.total_quantity,
    p.previous_cost = t.previous_cost,
    p.average_cost = t.average_cost;

DROP TEMPORARY TABLE tmp_product_costs;
